const getSliderAdjective = (value: number, type: string): string => {
  if (value >= 85) {
    switch (type) {
      case 'faceWidth': return "EXPANDED skeletal structure; broader facial architecture";
      case 'jawlineSharpness': return "HYPER-DEFINED; razor sharp shadow line at the jaw";
      case 'jawShape': return "ANGULAR L-SHAPED jaw; strong aristocratic bone structure";
      case 'eyeSize': return "EXTREME enlargement; doll-like iris and wide aperture";
      case 'lipThickness': return "PLUMPED; significant volume expansion for a filler look";
      case 'noseWidth': return "PRONOUNCED width; stronger nasal profile";
      case 'canthalTilt': return "UPWARD LIFT; feline tilt with outer corners raised";
      case 'cheekboneHeight': return "HIGH-PROJECTION; dramatic skeletal cheekbones";
      case 'eyeDistance': return "WIDE-SET; increased distance between orbital sockets";
      case 'noseBridge': return "PROMINENT bridge; high-profile Grecian architecture";
      case 'mouthCorners': return "LIFTED; permanent pleasant upturn at the lips";
      case 'lipCupidBow': return "SHARP M-SHAPE; surgically precise peaks";
      case 'skinAge': return "MATURE; realistic character lines and sagging texture";
      case 'glowIntensity': return "OIL-SLICK shine; hyper-reflective wet look";
      case 'blemishIntensity': return "RAW REALISM; heavy freckles and visible pores";
      case 'hairVolume': return "MASSIVE VOLUME; gravity-defying hair height";
      case 'hairShine': return "MIRROR SHINE; glossy salon-treated texture";
    }
  }
  if (value <= 15) {
    switch (type) {
      case 'faceWidth': return "ULTRA-SLENDER; physically narrow delicate skull";
      case 'jawlineSharpness': return "SOFT-FOCUS; rounded youthful jawline";
      case 'jawShape': return "V-LINE; soft rounded chin and reduced masseters";
      case 'eyeSize': return "MINIMALIST; smaller or hooded aesthetic eyes";
      case 'lipThickness': return "THIN; significantly reduced vertical lip height";
      case 'noseWidth': return "PINCHED; needle-thin nasal ala";
      case 'canthalTilt': return "DOWNWARD tilt; puppy-eye melancholic droop";
      case 'cheekboneHeight': return "FLAT midface; smooth suppressed cheekbones";
      case 'eyeDistance': return "CLOSE-SET; eyes positioned closer to the bridge";
      case 'noseBridge': return "FLAT button-nose profile; low nasal bridge";
      case 'skinAge': return "FETAL SMOOTH; zero pores or lines, perfect blur";
      case 'glowIntensity': return "ULTRA-MATTE; chalky velvet finish";
      case 'blemishIntensity': return "POWDER FINISH; synthetic poreless doll look";
    }
  }
  return `standard ${type}`;
};

const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline === undefined) return `FIXED: Maintain base ${type} exactly.`;
  const diff = current - baseline;
  if (Math.abs(diff) < 5) return `FIXED: No change to ${type}.`;
  const direction = diff > 0 ? "increase/sharpen/widen" : "decrease/soften/narrow";
  return `MORPH: Physically ${direction} the ${type} structure. Result: ${getSliderAdjective(current, type)}.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: { 
        parts: [
          { inlineData: { data, mimeType } }, 
          { text: "Detailed anatomical facial analysis. Determine percentages for features and return ONLY JSON." }
        ] 
      },
      config: { 
        responseMimeType: "application/json", 
        responseSchema: { 
          type: Type.OBJECT, 
          properties: { 
            skinTone: { type: Type.NUMBER }, 
            skinAge: { type: Type.NUMBER }, 
            eyeSize: { type: Type.NUMBER }, 
            eyeTilt: { type: Type.NUMBER }, 
            noseBridge: { type: Type.NUMBER }, 
            noseWidth: { type: Type.NUMBER }, 
            faceWidth: { type: Type.NUMBER }, 
            cheekboneHeight: { type: Type.NUMBER }, 
            jawShape: { type: Type.NUMBER }, 
            lipFullness: { type: Type.NUMBER }, 
            hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] }, 
            hairTexture: { type: Type.STRING, enum: ["straight", "curly"] } 
          }, 
          required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "noseWidth", "faceWidth", "cheekboneHeight", "jawShape", "lipFullness", "hairLength", "hairTexture"] 
        } 
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) { throw error; }
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, baseline, referenceImages } = state;
  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  let faceIns = "";
  if (isTargetedEdit && !editModes.face) {
    faceIns = "STRICT LOCK: Keep original facial structure, eyes, and bones perfectly identical.";
  } else if (referenceImages.face) {
    faceIns = "ANATOMICAL CLONING: Analyze FACIAL REF and replicate its exact bone structure and eye positioning onto the subject.";
  } else {
    const mods: string[] = [];
    const keys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'jawShape'];
    keys.forEach(k => mods.push(getDiffFeaturePrompt((features as any)[k], (baseline?.features as any)?.[k], k)));
    if (makeup.eyebrowStyle !== INITIAL_MAKEUP.eyebrowStyle) mods.push(`EYEBROWS: ${STYLE_DESCRIPTIONS[makeup.eyebrowStyle]}`);
    faceIns = `SURGERY: ${mods.join(" | ")}.`;
  }

  let makeIns = "";
  if (isTargetedEdit && !editModes.makeup) {
    makeIns = "STRICT LOCK: No makeup changes. Preserve original palette.";
  } else if (referenceImages.makeup) {
    makeIns = "MAKEUP TRANSFER: Copy exact eyeliner, eyeshadow, and lip colors from MAKEUP REF.";
  } else {
    makeIns = `STYLE: ${makeup.makeupStyle}. Liner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle]}. Lips: ${makeup.lipColor} ${makeup.lipStyle}.`;
  }

  let skinIns = "";
  if (isTargetedEdit && !editModes.skin) {
    skinIns = "STRICT LOCK: Keep original skin tone and texture.";
  } else if (referenceImages.skin) {
    skinIns = "DERMAL CLONE: Replicate skin texture and luminosity from SKIN REF.";
  } else {
    skinIns = `DERMATOLOGY: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Glow: ${skin.glowIntensity}%, Age: ${skin.skinAge}%.`;
  }

  let hairIns = "";
  if (isTargetedEdit && !editModes.hair) {
    hairIns = "STRICT LOCK: No hair changes.";
  } else if (referenceImages.hair) {
    hairIns = "HAIR REPLACEMENT: Copy length, texture, and color from HAIR REF.";
  } else {
    hairIns = `SALON: ${hair.hairLength} ${hair.hairTexture}. Top: ${hair.hairColorTop}, Bottom: ${hair.hairColorBottom}. Shine: ${hair.hairShine}%.`;
  }

  return `Task: Professional Editorial Retouching. 
    FACIAL GEOMETRY: ${faceIns} 
    DERMATOLOGY: ${skinIns} 
    HAIR ARTISTRY: ${hairIns} 
    MAKEUP ARTISTRY: ${makeIns}
    Mandate: Preserve background and lighting from BASE IMAGE. Output 2K Ultra HD realism.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const [header, data] = state.baseImage.split(';base64,');
    parts.push({ text: "INPUT BASE IMAGE" }, { inlineData: { data, mimeType: header.split(':')[1] } });
  }

  const addRef = (category: keyof typeof state.referenceImages, label: string) => {
    if (state.editModes[category] && state.referenceImages[category]) {
      const [header, data] = state.referenceImages[category]!.split(';base64,');
      parts.push({ text: `${label} REF IMAGE` }, { inlineData: { data, mimeType: header.split(':')[1] } });
    }
  };

  addRef('hair', 'HAIR');
  addRef('makeup', 'MAKEUP');
  addRef('skin', 'SKIN');
  addRef('face', 'FACIAL');

  try {
    const response = await ai.models.generateContent({ 
      model: 'gemini-3-pro-image-preview', 
      contents: { parts }, 
      config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } } 
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) { throw error; }
};

