import { GoogleGenAI, Type } from "@google/genai";
import { BeautyState } from "../types";
import { SKIN_TONES, SKIN_TEXTURES, INITIAL_MAKEUP, LIGHTING_MODES, BACKGROUNDS, OUTFITS } from "../constants";

const STYLE_DESCRIPTIONS: Record<string, string> = {
  'standard': 'soft oval arch', 'high_arch': 'high sharp arch', 'straight': 'youthful straight', 'curved': 'softly rounded',
  'natural': 'natural volume lashes', 'mascara': 'defined mascara lashes', 'idol': 'K-pop spiked lashes',
  'none': 'no eyeliner', 'tightline': 'subtle tightline', 'classic': 'classic wing', 'cat': 'sharp cat-eye', 'siren': 'fox-eye siren lift'
};

const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline === undefined) return `Maintain base ${type}.`;
  const diff = current - baseline;
  if (Math.abs(diff) < 5) return `No change to ${type}.`;
  return `${diff > 0 ? "Enhance/Widen" : "Soften/Narrow"} ${type} to intensity ${current}%.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [{ inlineData: { data, mimeType: header.split(':')[1] } }, { text: "Determine facial and skin percentages for analysis. JSON only." }] },
    config: { 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          skinTone: { type: Type.NUMBER }, skinAge: { type: Type.NUMBER }, eyeSize: { type: Type.NUMBER }, eyeTilt: { type: Type.NUMBER },
          noseBridge: { type: Type.NUMBER }, noseWidth: { type: Type.NUMBER }, faceWidth: { type: Type.NUMBER },
          cheekboneHeight: { type: Type.NUMBER }, jawShape: { type: Type.NUMBER }, lipFullness: { type: Type.NUMBER },
          hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] },
          hairTexture: { type: Type.STRING, enum: ["straight", "curly"] }
        },
        required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "noseWidth", "faceWidth", "cheekboneHeight", "jawShape", "lipFullness", "hairLength", "hairTexture"]
      }
    }
  });
  return JSON.parse(response.text || '{}');
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, environment, editModes, baseline } = state;

  const facePrompt = `SCULPT: ${Object.keys(features).map(k => getDiffFeaturePrompt((features as any)[k], (baseline?.features as any)?.[k], k)).join(", ")}.`;
  const skinPrompt = `DERMA: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skin.texture[0]}. Age: ${skin.skinAge}. Glow: ${skin.glowIntensity}%.`;
  const hairPrompt = `HAIR: ${hair.hairLength} ${hair.hairTexture}. Color: ${hair.hairColorTop} to ${hair.hairColorBottom}. Shine: ${hair.hairShine}%.`;
  const makePrompt = `MAKEUP: ${makeup.makeupStyle} vibe. Liner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle]}. Lips: ${makeup.lipColor} ${makeup.lipStyle}.`;
  const vibePrompt = `ATMOSPHERE: Lighting: ${LIGHTING_MODES.find(l => l.id === environment.lighting)?.prompt}. Background: ${BACKGROUNDS.find(b => b.id === environment.background)?.prompt}. Outfit: ${OUTFITS.find(o => o.id === environment.outfit)?.prompt}.`;

  return `High-end Digital Retouching Task. 
    FACIAL STRUCTURE: ${facePrompt}
    SKIN QUALITY: ${skinPrompt}
    HAIR ARTISTRY: ${hairPrompt}
    MAKEUP ARTISTRY: ${makePrompt}
    PHOTOGRAPHY & VIBE: ${vibePrompt}
    Mandate: High-resolution 2K realistic skin pores, cinematic editorial lighting, preserve core identity of base image.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const [header, data] = state.baseImage.split(';base64,');
    parts.push({ text: "INPUT BASE PORTRAIT" }, { inlineData: { data, mimeType: header.split(':')[1] } });
  }

  // Add reference images if modes are active
  Object.keys(state.referenceImages).forEach(cat => {
    if ((state.editModes as any)[cat] && (state.referenceImages as any)[cat]) {
      const [header, data] = (state.referenceImages as any)[cat].split(';base64,');
      parts.push({ text: `${cat.toUpperCase()} STYLE REFERENCE` }, { inlineData: { data, mimeType: header.split(':')[1] } });
    }
  });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (e) { throw e; }
};

