    Mandate: Strictly follow the physical structural changes requested. Preserve the base image's lighting and atmosphere unless vibe mode is active. High-resolution 2K realism.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const [header, data] = state.baseImage.split(';base64,');
    parts.push({ text: "INPUT BASE PORTRAIT" }, { inlineData: { data, mimeType: header.split(':')[1] } });
  }

  Object.keys(state.referenceImages).forEach(cat => {
    if ((state.editModes as any)[cat] && (state.referenceImages as any)[cat]) {
      const [header, data] = (state.referenceImages as any)[cat].split(';base64,');
      parts.push({ text: `${cat.toUpperCase()} STYLE REFERENCE IMAGE` }, { inlineData: { data, mimeType: header.split(':')[1] } });
    }
  });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (e) { throw e; }
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage, generateBeautyPrompt, analyzeImageAttributes } from './services/geminiService';
import { BeautyState } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP, INITIAL_ENVIRONMENT } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw, Search, Layout } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: { face: null, skin: null, hair: null, makeup: null },
    features: INITIAL_FEATURES,
    skin: { tone: 'natural', texture: ['Smooth'], skinAge: 20, glowIntensity: 50, blemishIntensity: 10 },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    environment: INITIAL_ENVIRONMENT,
    customPrompts: { face: '', skin: '', hair: '', makeup: '', vibe: '' },
    editModes: { face: false, skin: false, hair: false, makeup: false, vibe: false },
    aspectRatio: '1:1',
    baseline: undefined
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const applyAnalysis = async (data: any, originalImage: string) => {
    const skinToneId = data.skinTone < 20 ? 'porcelain' : data.skinTone < 40 ? 'fair' : data.skinTone < 60 ? 'natural' : data.skinTone < 80 ? 'tanned' : 'deep';
    const hairLen = (data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'medium' : 'long') as any;
    const hairTex = (data.hairTexture === 'straight' ? 'straight' : 's_curl') as any;
    const analyzedFeatures = { ...INITIAL_FEATURES, eyeSize: data.eyeSize ?? 50, canthalTilt: data.eyeTilt ?? 50, noseBridge: data.noseBridge ?? 50, noseWidth: data.noseWidth ?? 50, faceWidth: data.faceWidth ?? 50, cheekboneHeight: data.cheekboneHeight ?? 50, jawShape: data.jawShape ?? 50, lipThickness: data.lipFullness ?? 50 };
    const analyzedSkin = { ...state.skin, tone: skinToneId, skinAge: data.skinAge ?? 20 };
    const analyzedHair = { ...state.hair, hairLength: hairLen, hairTexture: hairTex };

    setState(prev => ({
      ...prev,
      baseImage: originalImage,
      features: analyzedFeatures,
      skin: analyzedSkin,
      hair: analyzedHair,
      baseline: { features: analyzedFeatures, skin: analyzedSkin, hair: { hairLength: hairLen, hairTexture: hairTex } }
    }));
  };

  const resetCategory = useCallback((category: 'face' | 'skin' | 'hair' | 'makeup') => {
    setState(prev => {
      const newState = { ...prev };
      const bl = prev.baseline;
      switch (category) {
        case 'face':
          newState.features = { ...INITIAL_FEATURES, ...(bl?.features || {}) };
          break;
        case 'skin':
          newState.skin = { ...prev.skin, ...(bl?.skin || { tone: 'natural', skinAge: 20 }) };
          break;
        case 'hair':
          newState.hair = { ...INITIAL_HAIR, ...(bl?.hair || { hairLength: 'long', hairTexture: 's_curl' }) };
          break;
        case 'makeup':
          newState.makeup = INITIAL_MAKEUP;
          break;
      }
      return newState;
    });
  }, []);

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      const result = await generateBeautyImage(state);
      if (result) setGeneratedImage(result);
      else setError("Synthesis failed. Try adjusting your settings.");
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) setNeedsKey(true);
      setError(err.message || "Synthesis error.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    updateState({ baseImage: generatedImage, baseline: { features: state.features, skin: state.skin, hair: { hairLength: state.hair.hairLength, hairTexture: state.hair.hairTexture } } });
    setGeneratedImage(null);
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            updateState({ baseImage: base64, baseline: undefined });
            setIsAnalyzing(true);
            try {
              const analysis = await analyzeImageAttributes(base64);
              applyAnalysis(analysis, base64);
            } catch (e) { setError("AI Analysis failed."); }
            finally { setIsAnalyzing(false); }
          };
          img.src = base64;
        } else {
          updateState({ referenceImages: { ...state.referenceImages, [type]: base64 } });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;

  return (
    <div className="flex flex-col h-screen bg-[#050505] overflow-hidden text-zinc-100 font-['Inter']">
      <header className="h-16 border-b border-white/5 flex items-center justify-between px-8 bg-black/40 backdrop-blur-3xl z-50">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-2xl shadow-indigo-600/30">
            <Sparkles className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight leading-none uppercase">BeautySynth <span className="text-indigo-500">Pro</span></h1>
            <p className="text-[9px] text-zinc-500 font-bold uppercase tracking-[0.2em] mt-1">High-End Digital Studio</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <button 
            onClick={handleGenerate}
            disabled={isGenerating || !state.baseImage}
            className={`flex items-center gap-3 px-8 py-3 rounded-2xl font-black text-sm tracking-wide transition-all ${
              isGenerating || !state.baseImage
              ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed' 
              : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-2xl shadow-indigo-600/40 border border-white/10'
            }`}
          >
            {isGenerating ? <div className="w-5 h-5 border-[3px] border-white/30 border-t-white rounded-full animate-spin" /> : <Zap className="w-4 h-4 fill-current" />}
            {isGenerating ? 'SYNTHESIZING...' : 'START SYNTHESIS'}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar state={state} updateState={updateState} onRefUpload={onFileUpload} onResetCategory={resetCategory} />

        <div className="flex-1 p-8 flex flex-col gap-8 overflow-hidden bg-[#09090b]">
          {error && (
            <div className="bg-rose-500/10 border border-rose-500/20 text-rose-400 px-5 py-3 rounded-2xl flex items-center justify-between text-xs font-bold shrink-0">
              <span className="flex items-center gap-2"><Trash2 className="w-4 h-4" /> {error}</span>
              <button onClick={() => setError(null)}>✕</button>
            </div>
          )}
          <div className="flex flex-col flex-1 min-h-0 gap-8">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 flex-1 min-h-0">
              <div className="bg-zinc-900/30 border border-white/5 rounded-[40px] overflow-hidden flex flex-col relative group shadow-2xl backdrop-blur-sm">
                <div className="p-5 border-b border-white/5 flex justify-between items-center bg-white/5">
                  <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Source Portrait</h3>
                  {isAnalyzing && <span className="text-[10px] font-black text-indigo-400 animate-pulse flex items-center gap-2"><Search className="w-3 h-3" /> ANALYZING</span>}
                </div>
                <div className="flex-1 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_#111,_#050505)]">
                  {state.baseImage ? (
                    <img src={state.baseImage} className={`max-w-full max-h-full object-contain transition-all duration-700 ${isAnalyzing ? 'opacity-40 grayscale blur-sm scale-95' : ''}`} alt="Base" />
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-6 group">
                      <div className="w-24 h-24 rounded-[32px] bg-zinc-900/50 flex items-center justify-center text-zinc-600 group-hover:text-indigo-400 border border-white/5 transition-all">
                        <Upload className="w-10 h-10" />
                      </div>
                      <span className="text-zinc-500 font-black text-xs uppercase tracking-widest">Upload Portrait</span>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} />
                    </label>
                  )}
                </div>
              </div>

              <div className="bg-zinc-900/30 border border-white/5 rounded-[40px] overflow-hidden flex flex-col relative shadow-2xl backdrop-blur-sm">
                <div className="p-5 border-b border-white/5 flex justify-between items-center bg-white/5">
                  <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Synthesized Result</h3>
                  <div className="flex gap-2">
                    {generatedImage && (
                      <>
                        <button onClick={handleUseAsBase} className="text-[10px] font-black uppercase tracking-widest text-indigo-400 flex items-center gap-2 px-4 py-1.5 rounded-full bg-indigo-500/10 border border-indigo-500/20 active:scale-95 transition-all">
                          <RefreshCcw className="w-3 h-3" /> Iterate
                        </button>
                        <button onMouseDown={() => setIsComparing(true)} onMouseUp={() => setIsComparing(false)} className="text-[10px] font-black uppercase tracking-widest text-zinc-400 flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/5 border border-white/10 select-none">
                          <Eye className="w-3 h-3" /> {isComparing ? 'Original' : 'Compare'}
                        </button>
                      </>
                    )}
                  </div>
                </div>
                <div className="flex-1 bg-black relative flex items-center justify-center group overflow-hidden">
                  <PreviewCanvas image={isComparing ? state.baseImage : generatedImage} loading={isGenerating} />
                </div>
              </div>
            </div>

            <div className="bg-zinc-900/30 border border-white/5 rounded-[32px] p-5 flex flex-col gap-3 shrink-0 h-32 shadow-2xl overflow-hidden backdrop-blur-sm">
              <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] flex items-center gap-2">
                <Zap className="w-3.5 h-3.5 text-indigo-500" /> Neural Aesthetic Context
              </h3>
              <div className="flex-1 overflow-y-auto text-[11px] text-zinc-400 leading-relaxed font-mono bg-black/40 p-4 rounded-2xl border border-white/5 scrollbar-thin">
                {currentPrompt}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

