      case 'jawShape': return "STRONG SQUARE JAW; angular masculine/aristocratic bone structure";
      case 'eyeSize': return "EXTREME DOLL-LIKE EYES; oversized irises";
      case 'lipThickness': return "MAXIMUM PLUMP; significant lip filler volume";
      case 'noseWidth': return "PRONOUNCED WIDE ALAE; broader nasal base";
      case 'canthalTilt': return "EXAGGERATED CAT-EYE; intense upward outer corner lift";
      case 'cheekboneHeight': return "HIGH SKELETAL PROJECTION; sharp fashion-model cheekbones";
      case 'eyeDistance': return "WIDE-SET; increased distance between orbital sockets";
      case 'noseBridge': return "PROMINENT HIGH BRIDGE; high-profile Grecian nose";
      case 'mouthCorners': return "LIFTED SMILE; permanent pleasant upturn";
      case 'lipCupidBow': return "SHARP M-SHAPE; extremely defined cupid's bow";
      case 'skinAge': return "MATURE; realistic character lines and aging";
    }
  }
  if (value <= 15) {
    switch (type) {
      case 'faceWidth': return "ULTRA-NARROW; physically slender delicate skull";
      case 'jawlineSharpness': return "SOFT FOCUS; rounded youthful transition from jaw to neck";
      case 'jawShape': return "V-LINE; extremely tapered chin and soft slim masseters";
      case 'eyeSize': return "MINIMALIST; smaller hooded aesthetic eyes";
      case 'lipThickness': return "THIN SLENDER LIPS; reduced vertical volume";
      case 'noseWidth': return "ULTRA-PINCHED; needle-thin nasal base";
      case 'canthalTilt': return "PUPPY-EYE DROOP; melancholic downward outer corners";
      case 'cheekboneHeight': return "FULL ROUNDED CHEEKS; youthful midface volume, soft apple-cheeks";
      case 'eyeDistance': return "CLOSE-SET; eyes closer to the nasal bridge";
      case 'noseBridge': return "FLAT BUTTON NOSE; low-profile bridge";
      case 'mouthCorners': return "NEUTRAL/DOWNTURNED; serious or stoic expression";
