const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline === undefined) return `FIXED: Maintain base ${type}.`;
  const diff = current - baseline;
  if (Math.abs(diff) < 5) return `FIXED: Keep original ${type}.`;
  const action = diff > 0 ? "Enhance/Widen/Sharpen" : "Soften/Reduce/Round";
  return `MORPH: ${action} ${type} to achieve ${getSliderAdjective(current, type)}.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [{ inlineData: { data, mimeType: header.split(':')[1] } }, { text: "Determine facial and skin percentages for analysis. JSON only." }] },
    config: { 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          skinTone: { type: Type.NUMBER }, skinAge: { type: Type.NUMBER }, eyeSize: { type: Type.NUMBER }, eyeTilt: { type: Type.NUMBER },
          noseBridge: { type: Type.NUMBER }, noseWidth: { type: Type.NUMBER }, faceWidth: { type: Type.NUMBER },
          cheekboneHeight: { type: Type.NUMBER }, jawShape: { type: Type.NUMBER }, lipFullness: { type: Type.NUMBER },
          hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] },
          hairTexture: { type: Type.STRING, enum: ["straight", "curly"] }
        },
        required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "noseWidth", "faceWidth", "cheekboneHeight", "jawShape", "lipFullness", "hairLength", "hairTexture"]
      }
    }
  });
  return JSON.parse(response.text || '{}');
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, environment, baseline } = state;

  const faceKeys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'jawShape', 'mouthCorners', 'lipCupidBow'];
  const faceIns = `SCULPT: ${faceKeys.map(k => getDiffFeaturePrompt((features as any)[k], (baseline?.features as any)?.[k], k)).join(" | ")}.`;

  const skinIns = `DERMA: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skin.texture[0]}. Age: ${skin.skinAge}. Glow: ${skin.glowIntensity}%.`;

  // Added bangStyle to the prompt
  const selectedBang = BANG_STYLES.find(b => b.id === hair.bangStyle)?.label || 'none';
  const hairIns = `SALON: ${hair.hairLength} ${hair.hairTexture}. Bangs: ${selectedBang} style fringe. Color: ${hair.hairColorTop} to ${hair.hairColorBottom}. Volume: ${hair.hairVolume}%, Shine: ${hair.hairShine}%.`;

  const makeIns = `MAKEUP: ${makeup.makeupStyle} vibe. Eyeliner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle]}. Lashes: ${STYLE_DESCRIPTIONS[makeup.eyelashStyle]}. Lips: ${makeup.lipColor} ${makeup.lipStyle}.`;

  // Property 'environment' now exists on BeautyState
  const vibeIns = `ATMOSPHERE: Lighting: ${LIGHTING_MODES.find(l => l.id === environment.lighting)?.prompt}. Background: ${BACKGROUNDS.find(b => b.id === environment.background)?.prompt}. Outfit: ${OUTFITS.find(o => o.id === environment.outfit)?.prompt}.`;

  return `Task: High-End Digital Editorial Retouching. 
    FACIAL GEOMETRY: ${faceIns} 
    SKIN QUALITY: ${skinIns} 
    HAIR ARTISTRY: ${hairIns} 
    MAKEUP ARTISTRY: ${makeIns}
    ENVIRONMENT: ${vibeIns}
    Mandate: Strictly follow the physical structural changes requested. Preserve the base image's lighting and atmosphere unless vibe mode is active. High-resolution 2K realism.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const [header, data] = state.baseImage.split(';base64,');
    parts.push({ text: "INPUT BASE PORTRAIT" }, { inlineData: { data, mimeType: header.split(':')[1] } });
  }

  Object.keys(state.referenceImages).forEach(cat => {
    if ((state.editModes as any)[cat] && (state.referenceImages as any)[cat]) {
      const [header, data] = (state.referenceImages as any)[cat].split(';base64,');
      parts.push({ text: `${cat.toUpperCase()} STYLE REFERENCE IMAGE` }, { inlineData: { data, mimeType: header.split(':')[1] } });
    }
  });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } }
    });
    // Iterate through response parts as per guidelines
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (e) { throw e; }
};

