const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: {
      face: null,
      skin: null,
      hair: null,
      makeup: null
    },
    features: INITIAL_FEATURES,
    skin: { 
      tone: 'natural', 
      texture: ['Smooth'],
      skinAge: 20,
      glowIntensity: 50,
      blemishIntensity: 10
    },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    customPrompts: {
      face: '',
      skin: '',
      hair: '',
      makeup: ''
    },
