export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, baseline, referenceImages } = state;
  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  let faceIns = "";
  if (isTargetedEdit && !editModes.face) {
    faceIns = "STRICT LOCK: Keep original facial structure and bones perfectly identical.";
  } else if (referenceImages.face) {
    faceIns = "ANATOMICAL CLONING: Analyze FACIAL REF and replicate its exact bone structure and eye positioning onto the subject.";
  } else {
    const mods: string[] = [];
    const keys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'jawShape', 'mouthCorners', 'lipCupidBow'];
    keys.forEach(k => mods.push(getDiffFeaturePrompt((features as any)[k], (baseline?.features as any)?.[k], k)));
    if (makeup.eyebrowStyle !== INITIAL_MAKEUP.eyebrowStyle) mods.push(`EYEBROWS: ${STYLE_DESCRIPTIONS[makeup.eyebrowStyle]}`);
    faceIns = `SURGERY: ${mods.join(" | ")}.`;
  }

  let makeIns = "";
  if (isTargetedEdit && !editModes.makeup) {
    makeIns = "STRICT LOCK: No makeup changes.";
  } else if (referenceImages.makeup) {
    makeIns = "MAKEUP TRANSFER: Copy exact eyeliner, eyeshadow, and lip colors from MAKEUP REF.";
  } else {
    makeIns = `STYLE: ${makeup.makeupStyle}. Liner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle]}. Lashes: ${STYLE_DESCRIPTIONS[makeup.eyelashStyle]}. Lips: ${makeup.lipColor} ${makeup.lipStyle}.`;
  }

  let skinIns = "";
  if (isTargetedEdit && !editModes.skin) {
    skinIns = "STRICT LOCK: Keep original skin tone and texture.";
  } else if (referenceImages.skin) {
    skinIns = "DERMAL CLONE: Replicate skin texture and luminosity from SKIN REF.";
  } else {
    skinIns = `DERMATOLOGY: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skin.texture[0]}. Glow: ${skin.glowIntensity}%, Age: ${skin.skinAge}%. Blemishes: ${skin.blemishIntensity}%.`;
  }

  let hairIns = "";
  if (isTargetedEdit && !editModes.hair) {
    hairIns = "STRICT LOCK: No hair changes.";
  } else if (referenceImages.hair) {
    hairIns = "HAIR REPLACEMENT: Copy length, texture, and color from HAIR REF.";
  } else {
    const selectedBang = BANG_STYLES.find(b => b.id === hair.bangStyle)?.label || 'none';
    hairIns = `SALON: ${hair.hairLength} ${hair.hairTexture}. Bangs: ${selectedBang} style fringe. Color: ${hair.hairColorTop} to ${hair.hairColorBottom}. Volume: ${hair.hairVolume}%, Shine: ${hair.hairShine}%.`;
  }

  return `Task: Professional Editorial Digital Retouching. 
    FACIAL GEOMETRY: ${faceIns} 
    DERMATOLOGY: ${skinIns} 
    HAIR ARTISTRY: ${hairIns} 
    MAKEUP ARTISTRY: ${makeIns}
    Mandate: Strictly follow the physical structural changes requested in SURGERY and SALON sections. Preserve background from BASE IMAGE. Output 2K Ultra HD realism.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const [header, data] = state.baseImage.split(';base64,');
    parts.push({ text: "INPUT BASE IMAGE" }, { inlineData: { data, mimeType: header.split(':')[1] } });
  }

  const addRef = (category: keyof typeof state.referenceImages, label: string) => {
    if (state.editModes[category] && state.referenceImages[category]) {
      const [header, data] = state.referenceImages[category]!.split(';base64,');
      parts.push({ text: `${label} REF IMAGE` }, { inlineData: { data, mimeType: header.split(':')[1] } });
    }
  };

  addRef('hair', 'HAIR');
  addRef('makeup', 'MAKEUP');
  addRef('skin', 'SKIN');
  addRef('face', 'FACIAL');

  try {
    const response = await ai.models.generateContent({ 
      model: 'gemini-3-pro-image-preview', 
      contents: { parts }, 
      config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } } 
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) { throw error; }
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage, generateBeautyPrompt, analyzeImageAttributes, analyzeResultingAesthetics } from './services/geminiService';
import { BeautyState } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw, Search, Activity, Copy, Check } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: {
      face: null,
      skin: null,
      hair: null,
      makeup: null
    },
    features: INITIAL_FEATURES,
    skin: { 
      tone: 'natural', 
      texture: ['Smooth'],
      skinAge: 20,
      glowIntensity: 50,
      blemishIntensity: 10
    },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    customPrompts: {
      face: '',
      skin: '',
      hair: '',
      makeup: ''
    },
    editModes: {
      face: false,
      skin: false,
      hair: false,
      makeup: false
    },
    aspectRatio: '1:1',
    baseline: undefined
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [resultAnalysis, setResultAnalysis] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  // 이미지 비율 계산 함수
  const calculateAspectRatio = (img: HTMLImageElement): any => {
    const ratio = img.width / img.height;
    const options: { label: string, value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  // 분석 데이터 적용 함수
  const applyAnalysis = async (data: any, originalImage: string, detectedRatio: any) => {
    const scale = (val: any) => {
      if (typeof val !== 'number') return 50;
      return val <= 1 ? Math.round(val * 100) : Math.round(val);
    };

    const skinToneVal = scale(data.skinTone);
    const skinToneId = skinToneVal < 20 ? 'porcelain' 
                     : skinToneVal < 40 ? 'fair' 
                     : skinToneVal < 60 ? 'natural' 
                     : skinToneVal < 80 ? 'tanned' 
                     : 'deep';

    const hairLen = (data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'medium' : 'long') as any;
    const hairTex = (data.hairTexture === 'straight' ? 'straight' : 's_curl') as any;

    const analyzedFeatures = {
      ...INITIAL_FEATURES,
      eyeSize: scale(data.eyeSize ?? 50),
      canthalTilt: scale(data.eyeTilt ?? 50),
      noseBridge: scale(data.noseBridge ?? 50),
      noseWidth: scale(data.noseWidth ?? 50),
      faceWidth: scale(data.faceWidth ?? 50),
      cheekboneHeight: scale(data.cheekboneHeight ?? 50),
      jawShape: scale(data.jawShape ?? 50),
      lipThickness: scale(data.lipFullness ?? 50),
    };

    const analyzedSkin = {
      ...state.skin,
      tone: skinToneId,
      skinAge: scale(data.skinAge ?? 20),
    };

    const analyzedHair = {
      ...state.hair,
      hairLength: hairLen,
      hairTexture: hairTex,
    };

    setState(prev => ({
      ...prev,
      baseImage: originalImage,
      aspectRatio: detectedRatio,
      features: analyzedFeatures,
      skin: analyzedSkin,
      hair: analyzedHair,
      baseline: {
        features: analyzedFeatures,
        skin: analyzedSkin,
        hair: {
          hairLength: hairLen,
          hairTexture: hairTex
        }
      }
    }));
  };

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      setResultAnalysis(null);
      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
        const analysis = await analyzeResultingAesthetics(result);
        setResultAnalysis(analysis);
      } else {
        setError("Synthesis failed. Please check your settings and try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An error occurred during synthesis.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_PRO_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    const currentAsBaseline = {
      features: { ...state.features },
      skin: { ...state.skin },
      hair: { hairLength: state.hair.hairLength, hairTexture: state.hair.hairTexture }
    };
    updateState({ baseImage: generatedImage, baseline: currentAsBaseline });
    setGeneratedImage(null);
    setResultAnalysis(null);
    setIsComparing(false);
  };

  const handleCopyAnalysis = () => {
    if (resultAnalysis) {
      navigator.clipboard.writeText(resultAnalysis);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    }
  };

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            const detectedRatio = calculateAspectRatio(img);
            // 업로드 시 즉시 상태 반영 및 분석 시작
            updateState({ baseImage: base64String, aspectRatio: detectedRatio, baseline: undefined });
            try {
              setIsAnalyzing(true);
              const analysis = await analyzeImageAttributes(base64String);
              await applyAnalysis(analysis, base64String, detectedRatio);
            } catch (err) {
              setError("AI analysis failed.");
            } finally {
              setIsAnalyzing(false);
            }
          };
          img.src = base64String;
        } else {
          updateState({ referenceImages: { ...state.referenceImages, [type]: base64String } });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;

  return (
    <div className="flex flex-col h-screen bg-[#050505] overflow-hidden text-zinc-100 selection:bg-indigo-500/30">
