          <div>
            <h1 className="text-xl font-black tracking-tight leading-none uppercase">BeautySynth <span className="text-indigo-500">PRO</span></h1>
            <p className="text-[9px] text-zinc-500 font-black uppercase tracking-[0.2em] mt-1">High-End Digital Aesthetics</p>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <button onClick={handleGenerate} disabled={isGenerating || !state.baseImage} className={`flex items-center gap-3 px-8 py-3 rounded-2xl font-black text-sm tracking-wide transition-all ${isGenerating || !state.baseImage ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-2xl shadow-indigo-600/40 border border-white/10'}`}>
            {isGenerating ? <div className="w-5 h-5 border-[3px] border-white/30 border-t-white rounded-full animate-spin" /> : <Zap className="w-4 h-4 fill-current" />}
            {isGenerating ? 'SYNTHESIZING...' : 'START SYNTHESIS'}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar state={state} updateState={updateState} onRefUpload={onFileUpload} onResetCategory={(cat) => {}} />
        <div className="flex-1 p-8 flex flex-col gap-8 overflow-hidden bg-[#09090b]">
          {error && <div className="bg-rose-500/10 border border-rose-500/20 text-rose-400 px-5 py-3 rounded-2xl flex items-center justify-between text-xs font-bold shrink-0"><span>{error}</span><button onClick={() => setError(null)}>✕</button></div>}
          <div className="flex flex-col flex-1 min-h-0 gap-8">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 flex-1 min-h-0">
