                    <button onClick={handleDownload} className="text-[10px] font-black text-emerald-400 bg-emerald-500/10 px-3 py-1.5 rounded-full border border-emerald-500/20 hover:bg-emerald-500/20 transition-all active:scale-95 uppercase tracking-widest">SAVE</button>
                    <button 
                      onMouseDown={() => setIsComparing(true)}
                      onMouseUp={() => setIsComparing(false)}
                      onMouseLeave={() => setIsComparing(false)}
                      className="text-[10px] font-black text-zinc-400 bg-white/5 px-3 py-1.5 rounded-full border border-white/10 hover:bg-white/10 transition-all active:scale-95 flex items-center gap-1.5 uppercase tracking-widest select-none"
                    >
                      {isComparing ? <EyeOff className="w-3 h-3" /> : <Eye className="w-3 h-3" />} COMPARE
                    </button>
                  </div>}
                </div>
                <div className="flex-1 bg-black relative flex items-center justify-center group overflow-hidden">
                  <PreviewCanvas image={isComparing ? state.baseImage : generatedImage} loading={isGenerating} onDownload={handleDownload} />
                  {isComparing && (
                    <div className="absolute top-4 left-4 px-3 py-1 bg-zinc-950/80 backdrop-blur-md border border-white/10 rounded-full text-[9px] font-black text-white tracking-widest uppercase z-20">Original Base</div>
