            <div className="bg-zinc-900/30 border border-white/5 rounded-[32px] p-5 flex flex-col gap-3 shrink-0 h-32 shadow-2xl overflow-hidden backdrop-blur-sm">
              <div className="flex items-center justify-between">
                <h3 className="text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-2">
                  {generatedImage && resultAnalysis ? (
                    <><Activity className="w-3.5 h-3.5 text-emerald-500" /><span className="text-emerald-500">AI Visual Analysis</span></>
                  ) : (
                    <><Zap className="w-3.5 h-3.5 text-indigo-500" /><span className="text-zinc-500">Neural Instruction Blueprint</span></>
