                {generatedImage && resultAnalysis && (
                  <button 
                    onClick={handleCopyAnalysis}
                    className="flex items-center gap-1.5 text-[9px] font-bold text-zinc-500 hover:text-emerald-400 transition-colors bg-white/5 px-2 py-1 rounded-md uppercase tracking-wider"
                  >
                    {isCopied ? <Check className="w-3 h-3 text-emerald-400" /> : <Copy className="w-3 h-3" />}
                    {isCopied ? 'COPIED' : 'COPY PROMPT'}
