import { generateBeautyImage, generateBeautyPrompt, analyzeImageAttributes, analyzeResultingAesthetics } from './services/geminiService';
import { BeautyState } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw, Search, Activity, Copy, Check, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: {
      face: null,
      skin: null,
      hair: null,
      makeup: null
    },
    features: INITIAL_FEATURES,
    skin: { 
      tone: 'natural', 
      texture: ['Smooth'],
      skinAge: 20,
      glowIntensity: 50,
      blemishIntensity: 10
    },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    customPrompts: {
      face: '',
      skin: '',
      hair: '',
      makeup: ''
    },
    editModes: {
      face: false,
      skin: false,
      hair: false,
      makeup: false
    },
    aspectRatio: '1:1',
    baseline: undefined
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [resultAnalysis, setResultAnalysis] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  // 이미지 비율 계산 함수
  const calculateAspectRatio = (img: HTMLImageElement): any => {
    const ratio = img.width / img.height;
    const options: { label: string, value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  // 분석 데이터 적용 함수
  const applyAnalysis = async (data: any, originalImage: string, detectedRatio: any) => {
    const scale = (val: any) => {
      if (typeof val !== 'number') return 50;
      return val <= 1 ? Math.round(val * 100) : Math.round(val);
    };

    const skinToneVal = scale(data.skinTone);
    const skinToneId = skinToneVal < 20 ? 'porcelain' 
                     : skinToneVal < 40 ? 'fair' 
                     : skinToneVal < 60 ? 'natural' 
                     : skinToneVal < 80 ? 'tanned' 
                     : 'deep';

    const hairLen = (data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'medium' : 'long') as any;
    const hairTex = (data.hairTexture === 'straight' ? 'straight' : 's_curl') as any;

    const analyzedFeatures = {
      ...INITIAL_FEATURES,
      eyeSize: scale(data.eyeSize ?? 50),
      canthalTilt: scale(data.eyeTilt ?? 50),
      noseBridge: scale(data.noseBridge ?? 50),
      noseWidth: scale(data.noseWidth ?? 50),
      faceWidth: scale(data.faceWidth ?? 50),
      cheekboneHeight: scale(data.cheekboneHeight ?? 50),
      jawShape: scale(data.jawShape ?? 50),
      lipThickness: scale(data.lipFullness ?? 50),
    };

    const analyzedSkin = {
      ...state.skin,
      tone: skinToneId,
      skinAge: scale(data.skinAge ?? 20),
    };

    const analyzedHair = {
      ...state.hair,
      hairLength: hairLen,
      hairTexture: hairTex,
    };

    setState(prev => ({
      ...prev,
      baseImage: originalImage,
      aspectRatio: detectedRatio,
      features: analyzedFeatures,
      skin: analyzedSkin,
      hair: analyzedHair,
      baseline: {
        features: analyzedFeatures,
        skin: analyzedSkin,
        hair: {
          hairLength: hairLen,
          hairTexture: hairTex
        }
      }
    }));
  };

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      setResultAnalysis(null);
      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
        const analysis = await analyzeResultingAesthetics(result);
        setResultAnalysis(analysis);
      } else {
        setError("Synthesis failed. Please check your settings and try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An error occurred during synthesis.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_PRO_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    const currentAsBaseline = {
      features: { ...state.features },
      skin: { ...state.skin },
      hair: { hairLength: state.hair.hairLength, hairTexture: state.hair.hairTexture }
    };
    updateState({ baseImage: generatedImage, baseline: currentAsBaseline });
    setGeneratedImage(null);
    setResultAnalysis(null);
    setIsComparing(false);
  };

  const handleCopyAnalysis = () => {
    if (resultAnalysis) {
      navigator.clipboard.writeText(resultAnalysis);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    }
  };

  const handleDeleteBaseImage = () => {
    updateState({ baseImage: null, baseline: undefined });
    setGeneratedImage(null);
    setResultAnalysis(null);
  };

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            const detectedRatio = calculateAspectRatio(img);
            // 업로드 시 즉시 상태 반영 및 분석 시작
            updateState({ baseImage: base64String, aspectRatio: detectedRatio, baseline: undefined });
            try {
              setIsAnalyzing(true);
              const analysis = await analyzeImageAttributes(base64String);
              await applyAnalysis(analysis, base64String, detectedRatio);
            } catch (err) {
              setError("AI analysis failed.");
            } finally {
              setIsAnalyzing(false);
            }
          };
          img.src = base64String;
        } else {
          updateState({ referenceImages: { ...state.referenceImages, [type]: base64String } });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;

  return (
    <div className="flex flex-col h-screen bg-[#050505] overflow-hidden text-zinc-100 selection:bg-indigo-500/30">
      <header className="h-16 border-b border-white/5 flex items-center justify-between px-8 bg-zinc-950/60 backdrop-blur-3xl z-50">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-2xl shadow-indigo-600/30">
            <Sparkles className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight leading-none uppercase">BeautySynth <span className="text-indigo-500">PRO</span></h1>
            <p className="text-[9px] text-zinc-500 font-black uppercase tracking-[0.2em] mt-1">High-End Digital Aesthetics</p>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <button onClick={handleGenerate} disabled={isGenerating || !state.baseImage} className={`flex items-center gap-3 px-8 py-3 rounded-2xl font-black text-sm tracking-wide transition-all ${isGenerating || !state.baseImage ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-2xl shadow-indigo-600/40 border border-white/10'}`}>
            {isGenerating ? <div className="w-5 h-5 border-[3px] border-white/30 border-t-white rounded-full animate-spin" /> : <Zap className="w-4 h-4 fill-current" />}
            {isGenerating ? 'SYNTHESIZING...' : 'START SYNTHESIS'}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar state={state} updateState={updateState} onRefUpload={onFileUpload} onResetCategory={(cat) => {}} />
        <div className="flex-1 p-8 flex flex-col gap-8 overflow-hidden bg-[#09090b]">
          {error && <div className="bg-rose-500/10 border border-rose-500/20 text-rose-400 px-5 py-3 rounded-2xl flex items-center justify-between text-xs font-bold shrink-0"><span>{error}</span><button onClick={() => setError(null)}>✕</button></div>}
          <div className="flex flex-col flex-1 min-h-0 gap-8">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 flex-1 min-h-0">
              <div className="bg-zinc-900/30 border border-white/5 rounded-[40px] overflow-hidden flex flex-col relative group shadow-2xl backdrop-blur-sm">
                <div className="p-5 border-b border-white/5 flex justify-between items-center bg-white/5">
                  <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Source Input</h3>
                  <div className="flex items-center gap-4">
                    {isAnalyzing && (
                      <span className="text-[9px] font-black text-indigo-400 flex items-center gap-1.5 animate-pulse uppercase">
                        <Search className="w-3 h-3" /> Face Analyzing...
                      </span>
                    )}
                    {state.baseImage && !isAnalyzing && (
                      <button 
                        onClick={handleDeleteBaseImage}
                        className="p-1.5 rounded-full hover:bg-rose-500/10 text-zinc-500 hover:text-rose-500 transition-all"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    )}
                  </div>
                </div>
                <div className="flex-1 flex items-center justify-center relative bg-black overflow-hidden">
                  {state.baseImage ? (
                    <>
                      <img src={state.baseImage} className={`max-w-full max-h-full object-contain transition-all duration-700 ${isAnalyzing ? 'opacity-40 grayscale blur-md scale-95' : 'opacity-100'}`} alt="Base" />
                      {isAnalyzing && (
                        <div className="absolute inset-0 z-10 flex flex-col items-center justify-center gap-4 bg-indigo-500/5 backdrop-blur-[2px]">
                          <div className="relative">
                            <Loader2 className="w-10 h-10 text-indigo-500 animate-spin" />
                            <div className="absolute inset-0 blur-xl bg-indigo-500/20 animate-pulse" />
                          </div>
                          <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em]">Face Analyzing</p>
                        </div>
                      )}
                    </>
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-6">
                      <div className="w-16 h-16 rounded-full bg-zinc-900 border border-white/5 flex items-center justify-center group-hover:bg-zinc-800 transition-all">
                        <Upload className="w-6 h-6 text-zinc-700 group-hover:text-indigo-500 transition-colors" />
                      </div>
                      <div className="text-center">
                        <p className="text-[11px] font-bold text-zinc-500 uppercase tracking-widest">Upload Portrait</p>
                        <p className="text-[9px] text-zinc-600 mt-1">RAW / JPEG / PNG</p>
                      </div>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} />
                    </label>
                  )}
                </div>
              </div>
              <div className="bg-zinc-900/30 border border-white/5 rounded-[40px] overflow-hidden flex flex-col relative shadow-2xl backdrop-blur-sm">
                <div className="p-5 border-b border-white/5 flex justify-between items-center bg-white/5">
                  <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Synthetic Output</h3>
                  {generatedImage && <div className="flex gap-2">
                    <button onClick={handleUseAsBase} className="text-[10px] font-black text-indigo-400 bg-indigo-500/10 px-3 py-1.5 rounded-full border border-indigo-500/20 hover:bg-indigo-500/20 transition-all active:scale-95 uppercase tracking-widest">BASE</button>
                    <button onClick={handleDownload} className="text-[10px] font-black text-emerald-400 bg-emerald-500/10 px-3 py-1.5 rounded-full border border-emerald-500/20 hover:bg-emerald-500/20 transition-all active:scale-95 uppercase tracking-widest">SAVE</button>
                    <button 
                      onMouseDown={() => setIsComparing(true)}
                      onMouseUp={() => setIsComparing(false)}
                      onMouseLeave={() => setIsComparing(false)}
                      className="text-[10px] font-black text-zinc-400 bg-white/5 px-3 py-1.5 rounded-full border border-white/10 hover:bg-white/10 transition-all active:scale-95 flex items-center gap-1.5 uppercase tracking-widest select-none"
                    >
                      {isComparing ? <EyeOff className="w-3 h-3" /> : <Eye className="w-3 h-3" />} COMPARE
                    </button>
                  </div>}
                </div>
                <div className="flex-1 bg-black relative flex items-center justify-center group overflow-hidden">
                  <PreviewCanvas image={isComparing ? state.baseImage : generatedImage} loading={isGenerating} onDownload={handleDownload} />
                  {isComparing && (
                    <div className="absolute top-4 left-4 px-3 py-1 bg-zinc-950/80 backdrop-blur-md border border-white/10 rounded-full text-[9px] font-black text-white tracking-widest uppercase z-20">Original Base</div>
                  )}
                </div>
              </div>
            </div>

            <div className="bg-zinc-900/30 border border-white/5 rounded-[32px] p-5 flex flex-col gap-3 shrink-0 h-32 shadow-2xl overflow-hidden backdrop-blur-sm">
              <div className="flex items-center justify-between">
                <h3 className="text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-2">
                  {generatedImage && resultAnalysis ? (
                    <><Activity className="w-3.5 h-3.5 text-emerald-500" /><span className="text-emerald-500">AI Visual Analysis</span></>
                  ) : (
                    <><Zap className="w-3.5 h-3.5 text-indigo-500" /><span className="text-zinc-500">Neural Instruction Blueprint</span></>
                  )}
                </h3>
                {generatedImage && resultAnalysis && (
                  <button 
                    onClick={handleCopyAnalysis}
                    className="flex items-center gap-1.5 text-[9px] font-bold text-zinc-500 hover:text-emerald-400 transition-colors bg-white/5 px-2 py-1 rounded-md uppercase tracking-wider"
                  >
                    {isCopied ? <Check className="w-3 h-3 text-emerald-400" /> : <Copy className="w-3 h-3" />}
                    {isCopied ? 'COPIED' : 'COPY PROMPT'}
                  </button>
                )}
              </div>
              <div className={`flex-1 overflow-y-auto text-[11px] leading-relaxed font-sans p-4 rounded-2xl border border-white/5 transition-all duration-500 ${generatedImage && resultAnalysis ? 'bg-emerald-500/5 text-emerald-100/80 italic' : 'bg-black/40 text-zinc-400 font-mono'}`}>
                {generatedImage && resultAnalysis ? (
                   <div className="whitespace-pre-wrap">
                     {resultAnalysis}
                   </div>
                ) : currentPrompt}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { BeautyState } from "../types";
import { SKIN_TONES, SKIN_TEXTURES, INITIAL_MAKEUP, BANG_STYLES } from "../constants";

const STYLE_DESCRIPTIONS: Record<string, string> = {
  'standard': 'standard soft eyebrow shape, natural oval arch',
  'high_arch': 'high arched eyebrows, sharp peak for a defined lift',
  'straight': 'K-beauty straight eyebrows, youthful linear shape',
  'curved': 'softly curved rounded eyebrows to soften angular features',
  'thin': 'thin and sleek 90s style elongated eyebrows',
  'soft_arch': 'soft angular arch peak suitable for diamond faces',
  'natural': 'natural length and volume eyelashes',
  'mascara': 'defined separated lashes with professional black mascara',
  'idol': 'K-pop idol style clumped spikes lashes, dolly effect',
  'volume': 'thick voluminous glamorous lashes',
  'under': 'emphasized lower lashes for big-eye expansion',
  'none': 'bare natural eyes without eyeliner',
  'tightline': 'invisible tightline filling only the upper waterline',
  'classic': 'classic natural winged eyeliner following eye shape',
  'puppy': 'downward puppy eyeliner for a sweet innocent look',
  'cat': 'sharp upward feline cat-eye lift',
  'siren': 'siren eyes fox definition with sharp inner corners',
  'bold': 'bold graphic thick black winged liner',
  'smoky': 'softly smudged and diffused smoky liner'
};

const getSliderAdjective = (value: number, type: string): string => {
  if (value >= 85) {
    switch (type) {
      case 'faceWidth': return "EXTREMELY BROAD; expansive facial architecture";
      case 'jawlineSharpness': return "HYPER-DEFINED; razor sharp shadow line at the jaw";
      case 'jawShape': return "STRONG SQUARE JAW; defined L-line aristocratic bone structure";
      case 'eyeSize': return "EXTREME enlargement; doll-like iris and wide aperture";
      case 'lipThickness': return "PLUMPED; significant volume expansion for a filler look";
      case 'noseWidth': return "PRONOUNCED width; stronger nasal profile";
      case 'canthalTilt': return "UPWARD LIFT; feline tilt with outer corners raised";
      case 'cheekboneHeight': return "HIGH-PROJECTION; dramatic skeletal fashion-model cheekbones";
      case 'eyeDistance': return "WIDE-SET; increased distance between orbital sockets";
      case 'noseBridge': return "PROMINENT bridge; high-profile Grecian architecture";
      case 'mouthCorners': return "UPTURNED SMILING CORNERS; pleasant and friendly expression with upturned lip ends";
      case 'lipCupidBow': return "SHARP M-SHAPE; surgically precise peaks";
      case 'skinAge': return "MATURE; realistic character lines and sagging texture";
    }
  }
  if (value <= 15) {
    switch (type) {
      case 'faceWidth': return "ULTRA-SLENDER; physically narrow delicate skull";
      case 'jawlineSharpness': return "SOFT-FOCUS; rounded youthful transition from jaw to neck";
      case 'jawShape': return "ROUNDED SOFT JAW; youthful facial fullness, complete absence of angularity, soft curved lower face";
      case 'eyeSize': return "MINIMALIST; smaller or hooded aesthetic eyes";
      case 'lipThickness': return "THIN; significantly reduced vertical lip height";
      case 'noseWidth': return "PINCHED; needle-thin nasal base";
      case 'canthalTilt': return "DOWNWARD tilt; puppy-eye melancholic droop";
      case 'cheekboneHeight': return "FLAT MIDFACE; smooth facial planes without skeletal protrusion, soft youthful flesh covering bone";
      case 'eyeDistance': return "CLOSE-SET; eyes positioned closer to the bridge";
      case 'noseBridge': return "FLAT button-nose profile; low nasal bridge";
      case 'skinAge': return "FETAL SMOOTH; zero pores or lines, perfect blur";
    }
  }
  // User feedback check: low values should mean fuller/rounder
  if (value < 40) {
    if (type === 'cheekboneHeight') return "softly rounded cheeks with gentle youthful volume, minimal bone definition";
    if (type === 'jawShape') return "softly rounded chin and jaw, oval youthful face shape";
  }
  return `standard ${type}`;
};

const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline === undefined) return `FIXED: Maintain base ${type} exactly.`;
  const diff = current - baseline;
  if (Math.abs(diff) < 5) return `FIXED: No change to ${type}.`;

  // Explicitly mapping the direction of change to morphological actions
  let action = "";
  if (diff > 0) {
    action = (type === 'mouthCorners') ? "lift and curve upwards" : "increase/sharpen/widen";
  } else {
    action = (type === 'jawShape' || type === 'cheekboneHeight') ? "add soft tissue volume and round out" : "decrease/soften/shrink";
  }

  return `MORPH: Physically ${action} the ${type} structure to achieve ${getSliderAdjective(current, type)}.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: { 
        parts: [
          { inlineData: { data, mimeType } }, 
          { text: "Detailed anatomical facial analysis. Determine facial and skin percentages as INTEGERS between 0 and 100 (e.g., 50, 85). Return ONLY JSON." }
        ] 
      },
      config: { 
        responseMimeType: "application/json", 
        responseSchema: { 
          type: Type.OBJECT, 
          properties: { 
            skinTone: { type: Type.NUMBER, description: "Skin tone percentage 0-100" }, 
            skinAge: { type: Type.NUMBER, description: "Skin age percentage 0-100" }, 
            eyeSize: { type: Type.NUMBER, description: "Eye size percentage 0-100" }, 
            eyeTilt: { type: Type.NUMBER, description: "Eye tilt percentage 0-100" }, 
            noseBridge: { type: Type.NUMBER, description: "Nose bridge height percentage 0-100" }, 
            noseWidth: { type: Type.NUMBER, description: "Nose width percentage 0-100" }, 
            faceWidth: { type: Type.NUMBER, description: "Face width percentage 0-100" }, 
            cheekboneHeight: { type: Type.NUMBER, description: "Cheekbone height percentage 0-100" }, 
            jawShape: { type: Type.NUMBER, description: "Jaw shape percentage 0-100" }, 
            lipFullness: { type: Type.NUMBER, description: "Lip fullness percentage 0-100" }, 
            hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] }, 
            hairTexture: { type: Type.STRING, enum: ["straight", "curly"] } 
          }, 
          required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "noseWidth", "faceWidth", "cheekboneHeight", "jawShape", "lipFullness", "hairLength", "hairTexture"] 
        } 
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) { throw error; }
};

export const analyzeResultingAesthetics = async (base64Image: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data, mimeType } },
          { text: "Analyze this beauty portrait and provide a high-quality, professional photography prompt that describes it. Focus on model characteristics, skin texture, lighting, camera settings (like lens), and overall mood. The output should be a single, detailed paragraph. Example style: 'portrait of a young brunette model with straight hair, clear skin texture, high detail skin with visible pores, taken with an 85 mm lens...'. Be very descriptive and professional." }
        ]
      }
    });
    return response.text || "Analysis unavailable.";
  } catch (error) {
    return "Result Analysis failed.";
  }
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, baseline, referenceImages } = state;
  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  let faceIns = "";
  if (isTargetedEdit && !editModes.face) {
    faceIns = "STRICT LOCK: Keep original facial structure and bones perfectly identical.";
  } else if (referenceImages.face) {
    faceIns = "ANATOMICAL CLONING: Analyze FACIAL REF and replicate its exact bone structure and eye positioning onto the subject.";
  } else {
    const mods: string[] = [];
    const keys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'jawShape', 'mouthCorners', 'lipCupidBow'];
    keys.forEach(k => mods.push(getDiffFeaturePrompt((features as any)[k], (baseline?.features as any)?.[k], k)));
    if (makeup.eyebrowStyle !== INITIAL_MAKEUP.eyebrowStyle) mods.push(`EYEBROWS: ${STYLE_DESCRIPTIONS[makeup.eyebrowStyle]}`);
    faceIns = `SURGERY: ${mods.join(" | ")}. Ensure any decrease in Jaw Shape or Cheekbone Height results in a fuller, rounder, softer youthful face rather than a sharper one. High Mouth Corners should translate to a visible pleasant smile.`;
  }

  let makeIns = "";
  if (isTargetedEdit && !editModes.makeup) {
    makeIns = "STRICT LOCK: No makeup changes.";
  } else if (referenceImages.makeup) {
    makeIns = "MAKEUP TRANSFER: Copy exact eyeliner, eyeshadow, and lip colors from MAKEUP REF.";
  } else {
    makeIns = `STYLE: ${makeup.makeupStyle}. Liner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle]}. Lashes: ${STYLE_DESCRIPTIONS[makeup.eyelashStyle]}. Lips: ${makeup.lipColor} ${makeup.lipStyle}.`;
  }

  let skinIns = "";
  if (isTargetedEdit && !editModes.skin) {
    skinIns = "STRICT LOCK: Keep original skin tone and texture.";
  } else if (referenceImages.skin) {
    skinIns = "DERMAL CLONE: Replicate skin texture and luminosity from SKIN REF.";
  } else {
    skinIns = `DERMATOLOGY: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skin.texture[0]}. Glow: ${skin.glowIntensity}%, Age: ${skin.skinAge}%. Blemishes: ${skin.blemishIntensity}%.`;
  }

  let hairIns = "";
  if (isTargetedEdit && !editModes.hair) {
    hairIns = "STRICT LOCK: No hair changes.";
  } else if (referenceImages.hair) {
    hairIns = "HAIR REPLACEMENT: Copy length, texture, and color from HAIR REF.";
  } else {
    const selectedBang = BANG_STYLES.find(b => b.id === hair.bangStyle)?.label || 'none';
    hairIns = `SALON: ${hair.hairLength} ${hair.hairTexture}. Bangs: ${selectedBang} style fringe. Color: ${hair.hairColorTop} to ${hair.hairColorBottom}. Volume: ${hair.hairVolume}%, Shine: ${hair.hairShine}%.`;
  }

  return `Task: Professional Editorial Digital Retouching. 
    FACIAL GEOMETRY: ${faceIns} 
    DERMATOLOGY: ${skinIns} 
    HAIR ARTISTRY: ${hairIns} 
    MAKEUP ARTISTRY: ${makeIns}
    Mandate: Strictly follow the physical structural changes requested in SURGERY and SALON sections. Preserve background from BASE IMAGE. Output 2K Ultra HD realism.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const [header, data] = state.baseImage.split(';base64,');
    parts.push({ text: "INPUT BASE IMAGE" }, { inlineData: { data, mimeType: header.split(':')[1] } });
  }

  const addRef = (category: keyof typeof state.referenceImages, label: string) => {
    if (state.editModes[category] && state.referenceImages[category]) {
      const [header, data] = state.referenceImages[category]!.split(';base64,');
      parts.push({ text: `${label} REF IMAGE` }, { inlineData: { data, mimeType: header.split(':')[1] } });
    }
  };

  addRef('hair', 'HAIR');
  addRef('makeup', 'MAKEUP');
  addRef('skin', 'SKIN');
  addRef('face', 'FACIAL');

  try {
    const response = await ai.models.generateContent({ 
      model: 'gemini-3-pro-image-preview', 
      contents: { parts }, 
      config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } } 
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) { throw error; }
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage, generateBeautyPrompt, analyzeImageAttributes, analyzeResultingAesthetics } from './services/geminiService';
import { BeautyState } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw, Search, Activity, Copy, Check, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: {
      face: null,
      skin: null,
      hair: null,
      makeup: null
    },
    features: INITIAL_FEATURES,
    skin: { 
      tone: 'natural', 
      texture: ['Smooth'],
      skinAge: 20,
      glowIntensity: 50,
      blemishIntensity: 10
    },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    customPrompts: {
      face: '',
      skin: '',
      hair: '',
      makeup: ''
    },
    editModes: {
      face: false,
      skin: false,
      hair: false,
      makeup: false
    },
    aspectRatio: '1:1',
    baseline: undefined
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [resultAnalysis, setResultAnalysis] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  // 이미지 비율 계산 함수
  const calculateAspectRatio = (img: HTMLImageElement): any => {
    const ratio = img.width / img.height;
    const options: { label: string, value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  // 분석 데이터 적용 함수
  const applyAnalysis = async (data: any, originalImage: string, detectedRatio: any) => {
    const scale = (val: any) => {
      if (typeof val !== 'number') return 50;
      return val <= 1 ? Math.round(val * 100) : Math.round(val);
    };

    const skinToneVal = scale(data.skinTone);
    const skinToneId = skinToneVal < 20 ? 'porcelain' 
                     : skinToneVal < 40 ? 'fair' 
                     : skinToneVal < 60 ? 'natural' 
                     : skinToneVal < 80 ? 'tanned' 
                     : 'deep';

    const hairLen = (data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'medium' : 'long') as any;
    const hairTex = (data.hairTexture === 'straight' ? 'straight' : 's_curl') as any;

    const analyzedFeatures = {
      ...INITIAL_FEATURES,
      eyeSize: scale(data.eyeSize ?? 50),
      canthalTilt: scale(data.eyeTilt ?? 50),
      noseBridge: scale(data.noseBridge ?? 50),
      noseWidth: scale(data.noseWidth ?? 50),
      faceWidth: scale(data.faceWidth ?? 50),
      cheekboneHeight: scale(data.cheekboneHeight ?? 50),
      jawShape: scale(data.jawShape ?? 50),
      lipThickness: scale(data.lipFullness ?? 50),
    };

    const analyzedSkin = {
      ...state.skin,
      tone: skinToneId,
      skinAge: scale(data.skinAge ?? 20),
    };

    const analyzedHair = {
      ...state.hair,
      hairLength: hairLen,
      hairTexture: hairTex,
    };

    setState(prev => ({
      ...prev,
      baseImage: originalImage,
      aspectRatio: detectedRatio,
      features: analyzedFeatures,
      skin: analyzedSkin,
      hair: analyzedHair,
      baseline: {
        features: analyzedFeatures,
        skin: analyzedSkin,
        hair: {
          hairLength: hairLen,
          hairTexture: hairTex
        }
      }
    }));
  };

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      setResultAnalysis(null);
      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
        const analysis = await analyzeResultingAesthetics(result);
        setResultAnalysis(analysis);
      } else {
        setError("Synthesis failed. Please check your settings and try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An error occurred during synthesis.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_PRO_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    const currentAsBaseline = {
      features: { ...state.features },
      skin: { ...state.skin },
      hair: { hairLength: state.hair.hairLength, hairTexture: state.hair.hairTexture }
    };
    updateState({ baseImage: generatedImage, baseline: currentAsBaseline });
    setGeneratedImage(null);
    setResultAnalysis(null);
    setIsComparing(false);
  };

  const handleCopyAnalysis = () => {
    if (resultAnalysis) {
      navigator.clipboard.writeText(resultAnalysis);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    }
  };

  const handleDeleteBaseImage = () => {
    updateState({ baseImage: null, baseline: undefined });
    setGeneratedImage(null);
    setResultAnalysis(null);
  };

  const handleResetCategory = (category: 'face' | 'skin' | 'hair' | 'makeup') => {
    setState(prev => {
      const updates: any = {};
      if (category === 'face') {
        updates.features = prev.baseline ? { ...INITIAL_FEATURES, ...prev.baseline.features } : INITIAL_FEATURES;
      } else if (category === 'skin') {
        updates.skin = prev.baseline ? { ...prev.skin, ...prev.baseline.skin } : { ...prev.skin, tone: 'natural', skinAge: 20 };
      } else if (category === 'hair') {
        updates.hair = prev.baseline && prev.baseline.hair ? { ...prev.hair, ...prev.baseline.hair } : INITIAL_HAIR;
      } else if (category === 'makeup') {
        updates.makeup = INITIAL_MAKEUP;
      }
      return { ...prev, ...updates };
    });
  };

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            const detectedRatio = calculateAspectRatio(img);
            // 업로드 시 즉시 상태 반영 및 분석 시작
            updateState({ baseImage: base64String, aspectRatio: detectedRatio, baseline: undefined });
            try {
              setIsAnalyzing(true);
              const analysis = await analyzeImageAttributes(base64String);
              await applyAnalysis(analysis, base64String, detectedRatio);
            } catch (err) {
              setError("AI analysis failed.");
            } finally {
              setIsAnalyzing(false);
            }
          };
          img.src = base64String;
        } else {
          updateState({ referenceImages: { ...state.referenceImages, [type]: base64String } });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;

  return (
    <div className="flex flex-col h-screen bg-[#050505] overflow-hidden text-zinc-100 selection:bg-indigo-500/30">
      <header className="h-16 border-b border-white/5 flex items-center justify-between px-8 bg-zinc-950/60 backdrop-blur-3xl z-50">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-2xl shadow-indigo-600/30">
            <Sparkles className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight leading-none uppercase">BeautySynth <span className="text-indigo-500">PRO</span></h1>
            <p className="text-[9px] text-zinc-500 font-black uppercase tracking-[0.2em] mt-1">High-End Digital Aesthetics</p>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <button onClick={handleGenerate} disabled={isGenerating || !state.baseImage} className={`flex items-center gap-3 px-8 py-3 rounded-2xl font-black text-sm tracking-wide transition-all ${isGenerating || !state.baseImage ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-2xl shadow-indigo-600/40 border border-white/10'}`}>
            {isGenerating ? <div className="w-5 h-5 border-[3px] border-white/30 border-t-white rounded-full animate-spin" /> : <Zap className="w-4 h-4 fill-current" />}
            {isGenerating ? 'SYNTHESIZING...' : 'START SYNTHESIS'}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar state={state} updateState={updateState} onRefUpload={onFileUpload} onResetCategory={handleResetCategory} />
        <div className="flex-1 p-8 flex flex-col gap-8 overflow-hidden bg-[#09090b]">
          {error && <div className="bg-rose-500/10 border border-rose-500/20 text-rose-400 px-5 py-3 rounded-2xl flex items-center justify-between text-xs font-bold shrink-0"><span>{error}</span><button onClick={() => setError(null)}>✕</button></div>}
          <div className="flex flex-col flex-1 min-h-0 gap-8">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 flex-1 min-h-0">
              <div className="bg-zinc-900/30 border border-white/5 rounded-[40px] overflow-hidden flex flex-col relative group shadow-2xl backdrop-blur-sm">
                <div className="p-5 border-b border-white/5 flex justify-between items-center bg-white/5">
                  <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Source Input</h3>
                  <div className="flex items-center gap-4">
                    {isAnalyzing && (
                      <span className="text-[9px] font-black text-indigo-400 flex items-center gap-1.5 animate-pulse uppercase">
                        <Search className="w-3 h-3" /> Face Analyzing...
                      </span>
                    )}
                    {state.baseImage && !isAnalyzing && (
                      <button 
                        onClick={handleDeleteBaseImage}
                        className="p-1.5 rounded-full hover:bg-rose-500/10 text-zinc-500 hover:text-rose-500 transition-all"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    )}
                  </div>
                </div>
                <div className="flex-1 flex items-center justify-center relative bg-black overflow-hidden">
                  {state.baseImage ? (
                    <>
                      <img src={state.baseImage} className={`max-w-full max-h-full object-contain transition-all duration-700 ${isAnalyzing ? 'opacity-40 grayscale blur-md scale-95' : 'opacity-100'}`} alt="Base" />
                      {isAnalyzing && (
                        <div className="absolute inset-0 z-10 flex flex-col items-center justify-center gap-4 bg-indigo-500/5 backdrop-blur-[2px]">
                          <div className="relative">
                            <Loader2 className="w-10 h-10 text-indigo-500 animate-spin" />
                            <div className="absolute inset-0 blur-xl bg-indigo-500/20 animate-pulse" />
                          </div>
                          <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em]">Face Analyzing</p>
                        </div>
                      )}
                    </>
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-6">
                      <div className="w-16 h-16 rounded-full bg-zinc-900 border border-white/5 flex items-center justify-center group-hover:bg-zinc-800 transition-all">
                        <Upload className="w-6 h-6 text-zinc-700 group-hover:text-indigo-500 transition-colors" />
                      </div>
                      <div className="text-center">
                        <p className="text-[11px] font-bold text-zinc-500 uppercase tracking-widest">Upload Portrait</p>
                        <p className="text-[9px] text-zinc-600 mt-1">RAW / JPEG / PNG</p>
                      </div>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} />
                    </label>
                  )}
                </div>
              </div>
              <div className="bg-zinc-900/30 border border-white/5 rounded-[40px] overflow-hidden flex flex-col relative shadow-2xl backdrop-blur-sm">
                <div className="p-5 border-b border-white/5 flex justify-between items-center bg-white/5">
                  <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Synthetic Output</h3>
                  {generatedImage && <div className="flex gap-2">
                    <button onClick={handleUseAsBase} className="text-[10px] font-black text-indigo-400 bg-indigo-500/10 px-3 py-1.5 rounded-full border border-indigo-500/20 hover:bg-indigo-500/20 transition-all active:scale-95 uppercase tracking-widest">BASE</button>
                    <button onClick={handleDownload} className="text-[10px] font-black text-emerald-400 bg-emerald-500/10 px-3 py-1.5 rounded-full border border-emerald-500/20 hover:bg-emerald-500/20 transition-all active:scale-95 uppercase tracking-widest">SAVE</button>
                    <button 
                      onMouseDown={() => setIsComparing(true)}
                      onMouseUp={() => setIsComparing(false)}
                      onMouseLeave={() => setIsComparing(false)}
                      className="text-[10px] font-black text-zinc-400 bg-white/5 px-3 py-1.5 rounded-full border border-white/10 hover:bg-white/10 transition-all active:scale-95 flex items-center gap-1.5 uppercase tracking-widest select-none"
                    >
                      {isComparing ? <EyeOff className="w-3 h-3" /> : <Eye className="w-3 h-3" />} COMPARE
                    </button>
                  </div>}
                </div>
                <div className="flex-1 bg-black relative flex items-center justify-center group overflow-hidden">
                  <PreviewCanvas image={isComparing ? state.baseImage : generatedImage} loading={isGenerating} onDownload={handleDownload} />
                  {isComparing && (
                    <div className="absolute top-4 left-4 px-3 py-1 bg-zinc-950/80 backdrop-blur-md border border-white/10 rounded-full text-[9px] font-black text-white tracking-widest uppercase z-20">Original Base</div>
                  )}
                </div>
              </div>
            </div>

            <div className="bg-zinc-900/30 border border-white/5 rounded-[32px] p-5 flex flex-col gap-3 shrink-0 h-32 shadow-2xl overflow-hidden backdrop-blur-sm">
              <div className="flex items-center justify-between">
                <h3 className="text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-2">
                  {generatedImage && resultAnalysis ? (
                    <><Activity className="w-3.5 h-3.5 text-emerald-500" /><span className="text-emerald-500">AI Visual Analysis</span></>
                  ) : (
                    <><Zap className="w-3.5 h-3.5 text-indigo-500" /><span className="text-zinc-500">Neural Instruction Blueprint</span></>
                  )}
                </h3>
                {generatedImage && resultAnalysis && (
                  <button 
                    onClick={handleCopyAnalysis}
                    className="flex items-center gap-1.5 text-[9px] font-bold text-zinc-500 hover:text-emerald-400 transition-colors bg-white/5 px-2 py-1 rounded-md uppercase tracking-wider"
                  >
                    {isCopied ? <Check className="w-3 h-3 text-emerald-400" /> : <Copy className="w-3 h-3" />}
                    {isCopied ? 'COPIED' : 'COPY PROMPT'}
                  </button>
                )}
              </div>
              <div className={`flex-1 overflow-y-auto text-[11px] leading-relaxed font-sans p-4 rounded-2xl border border-white/5 transition-all duration-500 ${generatedImage && resultAnalysis ? 'bg-emerald-500/5 text-emerald-100/80 italic' : 'bg-black/40 text-zinc-400 font-mono'}`}>
                {generatedImage && resultAnalysis ? (
                   <div className="whitespace-pre-wrap">
                     {resultAnalysis}
                   </div>
                ) : currentPrompt}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

