};

const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline === undefined) return `FIXED: Keep base ${type} exactly as is.`;
  const diff = current - baseline;
  const absDiff = Math.abs(diff);

  if (absDiff < 5) return `FIXED: No changes to ${type}.`;

  // 수치 변화가 클수록 더 강한 동사(Verb) 사용
  let intensityVerb = "slightly adjust";
  if (absDiff > 40) intensityVerb = "DRAMATICALLY OVERHAUL and EXAGGERATE";
  else if (absDiff > 20) intensityVerb = "SIGNIFICANTLY MORPH";
  else intensityVerb = "NOTICEABLY modify";

  let action = "";
  if (diff > 0) {
    action = (type === 'mouthCorners') ? "forcefully lift and curve upwards into a smile" : "increase/sharpen/widen";
  } else {
    action = (type === 'jawShape' || type === 'cheekboneHeight') ? "heavily add soft tissue/flesh and round out into a plump curve" : "decrease/soften/shrink/round";
  }

  return `PHYSICAL MORPH: ${intensityVerb} the ${type} to be ${getSliderAdjective(current, type)}.`;
};

