const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline === undefined) return `FIXED: No change to ${type}.`;
  const diff = current - baseline;
  const absDiff = Math.abs(diff);

  if (absDiff < 5) return `FIXED: Strictly keep the original ${type} unchanged.`;

  let intensityVerb = "slightly adjust";
  if (absDiff > 40) intensityVerb = "DRAMATICALLY OVERHAUL and EXAGGERATE";
  else if (absDiff > 20) intensityVerb = "SIGNIFICANTLY MORPH";
  else intensityVerb = "NOTICEABLY modify";

  let action = "";
  if (diff > 0) {
    action = (type === 'mouthCorners') ? "forcefully lift and curve upwards into a visible smile" : "increase/sharpen/widen";
  } else {
    action = (type === 'jawShape' || type === 'cheekboneHeight') ? "heavily add soft tissue/flesh and round out into a plump curve, removing skeletal definition" : "decrease/soften/shrink/round";
  }

  return `MORPH: ${intensityVerb} the ${type} to be ${getSliderAdjective(current, type)}.`;
};

