export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, baseline, referenceImages, customPrompts } = state;
  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  let faceIns = "";
  if (isTargetedEdit && !editModes.face) {
    faceIns = "STRICT LOCK: Keep original facial structure and bones perfectly identical. Do not change expression or facial shape.";
  } else if (referenceImages.face) {
    faceIns = "ANATOMICAL CLONING: Analyze FACIAL REF and replicate its exact bone structure and eye positioning onto the subject.";
  } else {
    const mods: string[] = [];
    const keys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'jawShape', 'mouthCorners', 'lipCupidBow'];
    keys.forEach(k => mods.push(getDiffFeaturePrompt((features as any)[k], (baseline?.features as any)?.[k], k)));
    if (makeup.eyebrowStyle !== INITIAL_MAKEUP.eyebrowStyle) mods.push(`EYEBROWS: ${STYLE_DESCRIPTIONS[makeup.eyebrowStyle]}`);

    faceIns = `SURGERY AND BONE RECONSTRUCTION: ${mods.join(" | ")}. CRITICAL: ONLY modify features marked as 'MORPH'. Features marked as 'FIXED' MUST be preserved exactly as in the base image. Do not add a smile unless mouthCorners is explicitly marked for MORPH with a high value. ${customPrompts.face ? `CUSTOM FACE NOTE: ${customPrompts.face}` : ''}`;
  }

  let makeIns = "";
  if (isTargetedEdit && !editModes.makeup) {
    makeIns = "STRICT LOCK: No makeup changes.";
  } else if (referenceImages.makeup) {
    makeIns = "MAKEUP TRANSFER: Copy exact eyeliner, eyeshadow, and lip colors from MAKEUP REF.";
  } else {
    const blushDesc = makeup.blushStyle !== 'none' 
      ? `Blush: Apply ${makeup.blushColor} in ${makeup.blushStyle} style with ${makeup.blushIntensity}% visible intensity on cheeks.` 
      : "Blush: None.";
    const contourDesc = `Contour/Shading: Apply structural dark shading with ${makeup.contourIntensity}% depth to sculpt the jawline and cheekbones.`;

    makeIns = `STYLE: ${makeup.makeupStyle}. Liner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle]}. Lashes: ${STYLE_DESCRIPTIONS[makeup.eyelashStyle]}. Lips: ${makeup.lipColor} ${makeup.lipStyle}. ${blushDesc} ${contourDesc}. Apply makeup with high saturation and editorial precision. ${customPrompts.makeup ? `CRITICAL ARTIST NOTE: ${customPrompts.makeup}` : ''}`;
  }

  let skinIns = "";
  if (isTargetedEdit && !editModes.skin) {
    skinIns = "STRICT LOCK: Keep original skin tone and texture.";
  } else if (referenceImages.skin) {
    skinIns = "DERMAL CLONE: Replicate skin texture and luminosity from SKIN REF.";
  } else {
    skinIns = `DERMATOLOGY: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skin.texture[0]}. Glow Intensity: ${skin.glowIntensity}%, Skin Age: ${skin.skinAge}%. Visible Blemishes: ${skin.blemishIntensity}%. ${customPrompts.skin ? `SKIN NOTE: ${customPrompts.skin}` : ''}`;
  }

  let hairIns = "";
  if (isTargetedEdit && !editModes.hair) {
    hairIns = "STRICT LOCK: No hair changes.";
  } else if (referenceImages.hair) {
    hairIns = "HAIR REPLACEMENT: Copy length, texture, and color from HAIR REF.";
  } else {
    const selectedBang = BANG_STYLES.find(b => b.id === hair.bangStyle)?.label || 'none';
    hairIns = `HAIR ARTISTRY: ${hair.hairLength} length ${hair.hairTexture} texture. Bangs: ${selectedBang} style fringe. Color: From ${hair.hairColorTop} to ${hair.hairColorBottom}. Volume: ${hair.hairVolume}%, Shine: ${hair.hairShine}%. ${customPrompts.hair ? `HAIR NOTE: ${customPrompts.hair}` : ''}`;
  }

  return `Task: Professional Editorial Digital Retouching and Morphological Synthesis. 
    FACIAL GEOMETRY & BONE: ${faceIns} 
    DERMATOLOGY: ${skinIns} 
    HAIR ARTISTRY: ${hairIns} 
    MAKEUP ARTISTRY: ${makeIns}
    CRITICAL MANDATE: Strictly implement the physical structural changes requested. If a feature is increased, make it significantly larger; if decreased, make it significantly smaller. PRESERVE ALL 'FIXED' FEATURES. Preserve background from BASE IMAGE. Output 2K Ultra HD realism.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const [header, data] = state.baseImage.split(';base64,');
    parts.push({ text: "INPUT BASE IMAGE" }, { inlineData: { data, mimeType: header.split(':')[1] } });
  }

  const addRef = (category: keyof typeof state.referenceImages, label: string) => {
    if (state.editModes[category] && state.referenceImages[category]) {
      const [header, data] = state.referenceImages[category]!.split(';base64,');
      parts.push({ text: `${label} REF IMAGE` }, { inlineData: { data, mimeType: header.split(':')[1] } });
    }
  };

  addRef('hair', 'HAIR');
  addRef('makeup', 'MAKEUP');
  addRef('skin', 'SKIN');
  addRef('face', 'FACIAL');

  try {
    const response = await ai.models.generateContent({ 
      model: 'gemini-3-pro-image-preview', 
      contents: { parts }, 
      config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } } 
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) { throw error; }
};

